const express = require('express');
const bodyParser = require('body-parser');
const app = express();
const port = 3000;

app.use(bodyParser.json());

// In-memory storage for level completion data and rewards
let levelData = {};
let rewards = {
    1: { type: 'coin', amount: 100 },
    2: { type: 'gem', amount: 5 },
    3: { type: 'powerup', amount: 1 }
};

// Endpoint to complete a level
app.post('/complete-level', (req, res) => {
    const { level, score, time } = req.body;

    if (!level || !score || !time) {
        return res.status(400).json({ error: 'Missing required fields' });
    }

    // Simulate validation of client-reported metrics
    if (score < 0 || time < 0) {
        return res.status(400).json({ error: 'Invalid score or time' });
    }

    levelData[level] = { score, time };

    const reward = rewards[level];
    if (!reward) {
        return res.status(400).json({ error: 'No reward available for this level' });
    }

    res.json({
        message: `Level ${level} completed successfully!`,
        reward
    });
});

// Endpoint to claim a reward
app.post('/claim-reward', (req, res) => {
    const { level } = req.body;

    if (!level) {
        return res.status(400).json({ error: 'Missing required field' });
    }

    const reward = rewards[level];
    if (!reward) {
        return res.status(400).json({ error: 'No reward available for this level' });
    }

    // Simulate validation of client-reported metrics
    if (!levelData[level]) {
        return res.status(400).json({ error: 'Level not completed' });
    }

    res.json({
        message: `Reward claimed successfully!`,
        reward
    });
});

app.listen(port, () => {
    console.log(`Server running at http://localhost:${port}`);
});